            this.dpsDomainObjectWithRailSupport = Prime.Base.ServiceStore<IVoltageService>.CreateVForceForPinTestConditionWithRails(domainNames, plist, domainPinAttributes, testCondition, railConfigurationNames, dlvrPinAttributes, someSessionContext);


